import { ShoppingCart, User } from "lucide-react";
import Image from "next/image";
import Logo from "@/assets/ila-logo.png"; // Update with your actual logo path

export default function Header() {
  return (
    <header className="flex items-center justify-between px-6 py-4 shadow-md bg-white">
      {/* Left: Menu */}
      <nav className="flex gap-6 text-sm font-medium text-gray-700">
        <a href="#" className="hover:text-amber-600">Menu</a>
        <a href="#" className="hover:text-amber-600">About</a>
        <a href="#" className="hover:text-amber-600">Contact</a>
      </nav>

      {/* Center: Logo */}
      <div className="absolute left-1/2 transform -translate-x-1/2">
        <Image src={Logo} alt="Ila Cafe" width={120} height={40} />
        {/* OR use text logo: */}
        {/* <h1 className="text-xl font-semibold tracking-wide">Ila Café</h1> */}
      </div>

      {/* Right: Icons */}
      <div className="flex gap-4 text-gray-700">
        <button className="hover:text-amber-600">
          <ShoppingCart size={22} />
        </button>
        <button className="hover:text-amber-600">
          <User size={22} />
        </button>
      </div>
    </header>
  );
}
